def count_range_sum(nums: list[int], lower: int, upper: int) -> int:
    n = len(nums)
    prefix = [0] * (n + 1)
    for i in range(n):
        prefix[i+1] = prefix[i] + nums[i]

    def merge_sort(arr: list[int], l: int, r: int) -> int:
        if l >= r:
            return 0
        mid = (l + r) // 2
        count = merge_sort(arr, l, mid) + merge_sort(arr, mid+1, r)

        left_ptr = l
        right_ptr = l
        for i in range(mid+1, r+1):
            while left_ptr <= mid and arr[left_ptr] < arr[i] - upper:
                left_ptr += 1
            while right_ptr <= mid and arr[right_ptr] <= arr[i] - lower:
                right_ptr += 1
            count += right_ptr - left_ptr

        merged = []
        i, j = l, mid+1
        while i <= mid and j <= r:
            if arr[i] <= arr[j]:
                merged.append(arr[i])
                i += 1
            else:
                merged.append(arr[j])
                j += 1
        merged.extend(arr[i:mid+1])
        merged.extend(arr[j:r+1])
        arr[l:r+1] = merged

        return count

    return merge_sort(prefix, 0, n)
