def max_coins(nums: list[int]) -> int:
    nums = [1] + nums + [1]
    n = len(nums)
    dp = [[0] * n for _ in range(n)]

    for length in range(2, n):
        for i in range(n - length):
            j = i + length
            for k in range(i + 1, j):
                dp[i][j] = max(dp[i][j], dp[i][k] + dp[k][j] + nums[i] * nums[k] * nums[j])

    return dp[0][n - 1]

import hashlib
import bisect

class ConsistentHashRing:
    def __init__(self, num_virtual_nodes: int = 150):
        self.num_virtual_nodes = num_virtual_nodes
        self._hashes = []
        self._hash_to_node = {}
        self._nodes = set()

    def add_node(self, node_id: str) -> None:
        if node_id in self._nodes:
            return
        self._nodes.add(node_id)
        for i in range(self.num_virtual_nodes):
            vnode = f"{node_id}#v{i}"
            h = int(hashlib.md5(vnode.encode()).hexdigest(), 16)
            bisect.insort(self._hashes, h)
            self._hash_to_node[h] = node_id

    def remove_node(self, node_id: str) -> None:
        if node_id not in self._nodes:
            raise KeyError(node_id)
        self._nodes.discard(node_id)
        self._hashes = [h for h in self._hashes if self._hash_to_node[h] != node_id]
        self._hash_to_node = {h: n for h, n in self._hash_to_node.items() if n != node_id}

    def get_node(self, key: str) -> str | None:
        if not self._nodes:
            return None
        h = int(hashlib.md5(key.encode()).hexdigest(), 16)
        idx = bisect.bisect_right(self._hashes, h)
        if idx == len(self._hashes):
            idx = 0
        return self._hash_to_node[self._hashes[idx]]

    def get_nodes_for_key(self, key: str, num_replicas: int = 3) -> list[str]:
        if not self._nodes:
            return []
        h = int(hashlib.md5(key.encode()).hexdigest(), 16)
        idx = bisect.bisect_right(self._hashes, h)
        if idx == len(self._hashes):
            idx = 0

        result = []
        seen = set()
        length = len(self._hashes)
        for _ in range(length):
            node = self._hash_to_node[self._hashes[idx]]
            if node not in seen:
                seen.add(node)
                result.append(node)
                if len(result) == num_replicas:
                    break
            idx = (idx + 1) % length
        return result

